class Solution:
    def countTestedDevices(self, batteryPercentages):
        arr = list(batteryPercentages)
        n = len(arr)
        count = 0
        for i in range(n):
            if arr[i] > 0:
                count += 1
                for j in range(i + 1, n):
                    arr[j] = max(0, arr[j] - 1)
        return count

solutions.python:
class Solution:
    def countTestedDevices(self, batteryPercentages):
        decrement = 0
        count = 0
        for b in batteryPercentages:
            if b - decrement > 0:
                count += 1
                decrement += 1
        return count

